1	/**
2	 * Pure reducer for the onboarding flow. Every state mutation goes through
3	 * here — no component or effect mutates state directly. Action variants are
4	 * documented in `types.ts`.
5	 */
6	
7	import { questions } from "../constants";
8	import type { OnboardingStage } from "../types/websocket";
9	import { initialState } from "./initial";
10	import type { Action, OnboardingState } from "./types";
11	
12	/**
13	 * When a `*_ready` / completion stage fires, the matching in-flight progress
14	 * slots are no longer relevant — drop them so the UI can't display stale text
15	 * after the step has completed.
16	 *
17	 * `inbox_scanning` is a multi-emit stage with no dedicated completion event;
18	 * any "after-inbox" stage signals it's done.
19	 */
20	const PROGRESS_CLEARED_BY: Partial<
21	  Record<OnboardingStage, readonly OnboardingStage[]>
22	> = {
23	  writing_style_ready: ["writing_style_progress"],
24	  triage_ready: ["triage_analyzing", "inbox_scanning"],
25	  todos_ready: ["todos_creating", "inbox_scanning"],
26	  workflows_ready: ["workflows_creating", "inbox_scanning"],
27	  social_profiles_ready: ["inbox_scanning"],
28	  complete: [
29	    "inbox_scanning",
30	    "writing_style_progress",
31	    "triage_analyzing",
32	    "todos_creating",
33	    "workflows_creating",
34	  ],
35	};
36	
37	function clearProgressSlots(
38	  progressByStage: OnboardingState["progressByStage"],
39	  completed: OnboardingStage,
40	): OnboardingState["progressByStage"] {
41	  const toClear = PROGRESS_CLEARED_BY[completed];
42	  if (!toClear) return progressByStage;
43	  let next: OnboardingState["progressByStage"] | null = null;
44	  for (const stage of toClear) {
45	    if (stage in progressByStage) {
46	      next = next ?? { ...progressByStage };
47	      delete next[stage];
48	    }
49	  }
50	  return next ?? progressByStage;
51	}
52	
53	export function reducer(
54	  state: OnboardingState,
55	  action: Action,
56	): OnboardingState {
57	  switch (action.type) {
58	    case "draftText":
59	      return { ...state, draftText: action.value };
60	
61	    case "draftProfession":
62	      return { ...state, draftProfession: action.value };
63	
64	    case "answer": {
65	      const responses = {
66	        ...state.responses,
67	        [action.field]: action.value,
68	      };
69	      const isLast = state.questionIndex >= questions.length - 1;
70	      return {
71	        ...state,
72	        responses,
73	        questionIndex: isLast ? questions.length : state.questionIndex + 1,
74	        draftText: "",
75	        draftProfession: null,
76	      };
77	    }
78	
79	    case "submitError":
80	      return { ...state, submissionError: true };
81	
82	    case "retrySubmit":
83	      return { ...state, submissionError: false };
84	
85	    case "serverSnapshot":
86	      return { ...state, server: action.data };
87	
88	    case "serverPatch":
89	      return {
90	        ...state,
91	        server: { ...(state.server ?? {}), ...action.patch },
92	      };
93	
94	    case "progress":
95	      return {
96	        ...state,
97	        progressByStage: {
98	          ...state.progressByStage,
99	          [action.stage]: action.message,
100	        },
101	      };
102	
103	    case "stageComplete": {
104	      const alreadyMarked = state.completedStages.has(action.stage);
105	      const nextProgress = clearProgressSlots(
106	        state.progressByStage,
107	        action.stage,
108	      );
109	      if (alreadyMarked && nextProgress === state.progressByStage) {
110	        return state;
111	      }
112	      const completedStages = alreadyMarked
113	        ? state.completedStages
114	        : new Set(state.completedStages).add(action.stage);
115	      return {
116	        ...state,
117	        completedStages,
118	        progressByStage: nextProgress,
119	      };
120	    }
121	
122	    case "ackWriting":
123	      return { ...state, ackedWritingStyle: true };
124	
125	    case "ackTodos":
126	      return { ...state, ackedTodos: true };
127	
128	    case "confirmWorkflows":
129	      return { ...state, workflowsConfirmed: true };
130	
131	    case "platformConnected":
132	      return {
133	        ...state,
134	        connectedPlatform: action.platform,
135	        workflowsConfirmed: true,
136	      };
137	
138	    case "executeTodo":
139	      return {
140	        ...state,
141	        ackedTodos: true,
142	        todoExecutionMessage: action.message,
143	      };
144	
145	    case "clearTodoExecutionMessage":
146	      return { ...state, todoExecutionMessage: null };
147	
148	    case "restartStart":
149	      return {
150	        ...initialState,
151	        isRestarting: true,
152	      };
153	
154	    case "restartDone":
155	      return { ...state, isRestarting: false };
156	
157	    case "hydrate":
158	      return { ...state, ...action.partial };
159	
160	    case "reset":
161	      return initialState;
162	  }
