1	/**
2	 * Drives the live backend connection during onboarding: fetches the initial
3	 * personalization snapshot via REST, opens a WebSocket for stage events, and
4	 * falls back to REST polling if the socket goes silent.
5	 */
6	
7	"use client";
8	
9	import { type Dispatch, useEffect, useRef } from "react";
10	
11	import { getPersonalization } from "../api/onboardingApi";
12	import type { Action, OnboardingState, Stage } from "../state/types";
13	import type { OnboardingStage, StagePayloads } from "../types/websocket";
14	
15	const MAX_RECONNECT_ATTEMPTS = 10;
16	const RECONNECT_BASE_DELAY_MS = 1000;
17	// If the WS connects but stays silent past this window, kick off a REST
18	// poll so the user isn't stuck behind a silent socket.
19	const WS_SILENCE_FALLBACK_MS = 5000;
20	// Once polling, refetch the snapshot at this cadence. Cleared the moment
21	// any WS event lands.
22	const POLL_INTERVAL_MS = 3000;
23	
24	function getWsUrl(): string {
25	  const base =
26	    process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:8000/api/v1/";
27	  return (
28	    base.replace("http://", "ws://").replace("https://", "wss://") +
29	    "ws/connect"
30	  );
31	}
32	
33	/**
34	 * Discriminated-union envelope: narrowing on `stage` automatically narrows
35	 * `payload`, so handlers can be typed without per-case `as` casts.
36	 */
37	type StageEnvelope = {
38	  [K in OnboardingStage]: { stage: K; payload: StagePayloads[K] };
39	}[OnboardingStage];
40	
41	/**
42	 * Activates once the user is past Q&A/focus. Fetches `/personalization`
43	 * once, then routes WS `onboarding_stage` events into reducer dispatches.
44	 * If the socket connects but stays silent for `WS_SILENCE_FALLBACK_MS`,
45	 * starts polling `/personalization` every `POLL_INTERVAL_MS` until the WS
46	 * sends an event or a snapshot with a conversation id arrives. Reconnects
47	 * with exponential backoff up to MAX_RECONNECT_ATTEMPTS.
48	 */
49	export function useBackendSync(
50	  state: OnboardingState,
51	  stage: Stage,
52	  dispatch: Dispatch<Action>,
53	): void {
54	  // Active once we've moved past the Q&A composer stages.
55	  const active =
56	    stage !== "questions" && stage !== "focus" && !state.isRestarting;
57	
58	  const dispatchRef = useRef(dispatch);
59	  const isRestartingRef = useRef(state.isRestarting);
60	
61	  useEffect(() => {
62	    dispatchRef.current = dispatch;
63	  });
64	  useEffect(() => {
65	    isRestartingRef.current = state.isRestarting;
66	  });
67	
68	  useEffect(() => {
69	    if (!active) return;
70	
71	    let aborted = false;
72	    let snapshotResolved = false;
73	    const buffer: StageEnvelope[] = [];
74	    let ws: WebSocket | null = null;
75	    let reconnectAttempts = 0;
76	    let reconnectTimer: ReturnType<typeof setTimeout> | null = null;
77	    let silenceTimer: ReturnType<typeof setTimeout> | null = null;
78	    let pollTimer: ReturnType<typeof setInterval> | null = null;
79	    let silenceFallbackUsed = false;
80	    let wsReceivedEvent = false;
81	    let closed = false;
82	
83	    type StageHandlers = {
84	      [K in OnboardingStage]: (payload: StagePayloads[K]) => void;
85	    };
86	
87	    const dispatchProgress = (
88	      stage: OnboardingStage,
89	      status_text: string | undefined,
90	    ): void => {
91	      if (!status_text) {
92	        console.warn(
93	          `[onboarding:ws] ${stage} progress event with no status_text — backend likely stale`,
94	        );
95	        return;
96	      }
97	      dispatchRef.current({ type: "progress", stage, message: status_text });
98	    };
99	
100	    const handlers: StageHandlers = {
101	      inbox_scanning: (p) => dispatchProgress("inbox_scanning", p.status_text),
102	      writing_style_progress: (p) =>
103	        dispatchProgress("writing_style_progress", p.status_text),
104	      triage_analyzing: (p) =>
105	        dispatchProgress("triage_analyzing", p.status_text),
106	      todos_creating: (p) => dispatchProgress("todos_creating", p.status_text),
107	      workflows_creating: (p) =>
108	        dispatchProgress("workflows_creating", p.status_text),
109	      writing_style_ready: (p) => {
110	        // Backend emits this stage even when no style could be learned
111	        // (no Gmail, insufficient sent emails, LLM failure) so the pipeline
112	        // has a definitive completion signal. In those cases style_summary
113	        // is null and there's nothing to reveal — store null, not an empty
114	        // object, so getStage's truthy check skips revealWriting cleanly.
115	        const summary = p.style_summary?.trim();
116	        dispatchRef.current({
117	          type: "serverPatch",
118	          patch: {
119	            writing_style: summary
120	              ? { style_summary: summary, example: p.example ?? null }
121	              : null,
122	          },
123	        });
124	      },
125	      social_profiles_ready: (p) => {
126	        dispatchRef.current({
127	          type: "serverPatch",
128	          patch: { social_profiles: p.profiles },
129	        });
130	      },
131	      triage_ready: (p) => {
132	        dispatchRef.current({
133	          type: "serverPatch",
134	          patch: { triage_summary: p },
135	        });
136	      },
137	      todos_ready: (p) => {
138	        dispatchRef.current({
139	          type: "serverPatch",
140	          patch: { onboarding_todos: p.todos },
141	        });
142	      },
143	      workflows_ready: (p) => {
144	        dispatchRef.current({
145	          type: "serverPatch",
146	          patch: {
147	            suggested_workflows: p.workflows.map((w) => ({
148	              id: w.id ?? "",
149	              title: w.title,
150	              description: w.description ?? "",
151	              steps: (w.categories ?? []).map((c) => ({ category: c })),
152	              trigger: w.trigger,
153	            })),
154	          },
155	        });
156	      },
157	      holo_ready: () => {
158	        getPersonalization()
159	          .then((data) => {
160	            if (aborted || isRestartingRef.current) return;
161	            dispatchRef.current({ type: "serverSnapshot", data });
162	            dispatchRef.current({
163	              type: "stageComplete",
164	              stage: "holo_ready",
165	            });
166	          })
167	          .catch(() => {
168	            // swallow — WS reconnect or poll will retry
169	          });
170	      },
171	      complete: (p) => {
172	        dispatchRef.current({
173	          type: "serverPatch",
174	          patch: {
175	            first_message_conversation_id: p.conversation_id ?? undefined,
176	            phase: "personalization_complete",
177	          },
178	        });
179	        closeWs();
180	      },
181	    };
182	
183	    /**
184	     * Calls the right handler for an envelope. Generic so TS narrows
185	     * `StagePayloads[K]` against `K` — no per-case `as` casts needed.
186	     */
187	    const dispatchEnvelope = <K extends OnboardingStage>(
188	      stage: K,
189	      payload: StagePayloads[K],
190	    ) => {
191	      handlers[stage](payload);
192	    };
193	
194	    const handleStage = (envelope: StageEnvelope) => {
195	      if (aborted) return;
196	      if (isRestartingRef.current) return;
197	
198	      // holo_ready dispatches stageComplete itself once the REST follow-up
199	      // resolves; everything else marks complete synchronously here.
200	      if (envelope.stage !== "holo_ready") {
201	        dispatchRef.current({
202	          type: "stageComplete",
203	          stage: envelope.stage,
204	        });
205	      }
206	      dispatchEnvelope(envelope.stage, envelope.payload);
207	    };
208	
209	    const flushBuffer = () => {
210	      while (buffer.length > 0) {
211	        const next = buffer.shift();
212	        if (next) handleStage(next);
213	      }
214	    };
215	
216	    const stopPoll = () => {
217	      if (pollTimer) {
218	        clearInterval(pollTimer);
219	        pollTimer = null;
220	      }
221	    };
222	
223	    const closeWs = () => {
224	      closed = true;
225	      if (reconnectTimer) {
226	        clearTimeout(reconnectTimer);
227	        reconnectTimer = null;
228	      }
229	      if (silenceTimer) {
230	        clearTimeout(silenceTimer);
231	        silenceTimer = null;
232	      }
233	      stopPoll();
234	      if (ws) {
235	        ws.close();
236	        ws = null;
237	      }
